#!/bin/bash
set -euo pipefail
cd /app

python3 << 'PYEOF'
import json
import os
import glob
import hashlib

DATA_DIR = "/app/api_specs"
OUTPUT_PATH = "/app/api_compat_report.json"

def load_json(path):
    with open(path) as f:
        return json.load(f)

config = load_json(os.path.join(DATA_DIR, "config.json"))
resources_list = load_json(os.path.join(DATA_DIR, "resources.json"))
scope_weights = config["scope_weights"]

resources_by_id = {r["id"]: r for r in resources_list}

version_files = sorted(glob.glob(os.path.join(DATA_DIR, "versions", "*.json")))
versions = []
for vf in version_files:
    versions.append(load_json(vf))
versions.sort(key=lambda v: (v["release_date"], v["version_name"]))
version_order = [v["version_name"] for v in versions]
version_dates = {v["version_name"]: v["release_date"] for v in versions}

endpoint_files = sorted(glob.glob(os.path.join(DATA_DIR, "endpoints", "*.json")))
endpoints = []
for ef in endpoint_files:
    endpoints.append(load_json(ef))
endpoints.sort(key=lambda e: e["endpoint_id"])

# === TWIST 1: Inherited Deprecation (Rule 2) ===

def get_ancestors(resource_id):
    chain = []
    current = resource_id
    visited = set()
    while current is not None and current not in visited:
        visited.add(current)
        res = resources_by_id.get(current)
        if res is None:
            break
        chain.append(res)
        current = res.get("parent_id")
    return chain

def compute_effective_deprecation(resource_id):
    chain = get_ancestors(resource_id)
    best = None
    best_source = None
    best_from = None

    own_res = resources_by_id.get(resource_id)
    if own_res and own_res.get("deprecation"):
        own_dep = own_res["deprecation"]
        best = own_dep
        best_source = "own"
        best_from = None

    for res in chain:
        if res["id"] == resource_id:
            continue
        dep = res.get("deprecation")
        if dep is None:
            continue
        if best is None:
            best = dep
            best_source = "inherited"
            best_from = res["id"]
        else:
            if dep["sunset_at"] < best["sunset_at"]:
                best = dep
                best_source = "inherited"
                best_from = res["id"]
            elif dep["sunset_at"] == best["sunset_at"] and best_source == "inherited":
                pass

    if best is None:
        return None

    return {
        "effective_sunset_at": best["sunset_at"],
        "effective_deprecated_at": best["deprecated_at"],
        "deprecation_source": best_source,
        "inherited_from": best_from
    }

resource_deprecations = []
for res in resources_list:
    eff = compute_effective_deprecation(res["id"])
    if eff is not None:
        resource_deprecations.append({
            "resource_id": res["id"],
            "deprecation_source": eff["deprecation_source"],
            "effective_deprecated_at": eff["effective_deprecated_at"],
            "effective_sunset_at": eff["effective_sunset_at"],
            "inherited_from": eff["inherited_from"]
        })
resource_deprecations.sort(key=lambda x: x["resource_id"])

resource_eff_dep = {}
for rd in resource_deprecations:
    resource_eff_dep[rd["resource_id"]] = rd

# === Rule 3: Change Detection ===

def detect_field_changes(fields_old, fields_new):
    changes = []
    old_by_name = {f["name"]: f for f in fields_old}
    new_by_name = {f["name"]: f for f in fields_new}

    all_names = sorted(set(list(old_by_name.keys()) + list(new_by_name.keys())))

    for name in all_names:
        in_old = name in old_by_name
        in_new = name in new_by_name

        if in_old and not in_new:
            changes.append(("field_removed", name))
        elif not in_old and in_new:
            changes.append(("field_added", name))
        else:
            old_f = old_by_name[name]
            new_f = new_by_name[name]
            if old_f["type"] != new_f["type"]:
                changes.append(("field_type_changed", name))
            if old_f["required"] != new_f["required"]:
                changes.append(("field_required_changed", name))
            old_default = json.dumps(old_f.get("default_value"), sort_keys=True)
            new_default = json.dumps(new_f.get("default_value"), sort_keys=True)
            if old_default != new_default:
                changes.append(("field_default_changed", name))

    return changes

def detect_param_changes(params_old, params_new):
    changes = []
    old_by_name = {p["name"]: p for p in params_old}
    new_by_name = {p["name"]: p for p in params_new}

    all_names = sorted(set(list(old_by_name.keys()) + list(new_by_name.keys())))

    for name in all_names:
        in_old = name in old_by_name
        in_new = name in new_by_name

        if in_old and not in_new:
            changes.append(("param_removed", name))
        elif not in_old and in_new:
            changes.append(("param_added", name))
        else:
            old_p = old_by_name[name]
            new_p = new_by_name[name]
            if old_p["type"] != new_p["type"]:
                changes.append(("param_type_changed", name))
            if old_p["required"] != new_p["required"]:
                changes.append(("param_required_changed", name))

    return changes

def is_breaking_by_scope(change_type, scope, fields_old, fields_new, field_name):
    matrix = {
        "field_removed":         {"public": True, "partner": True, "internal": False},
        "field_type_changed":    {"public": True, "partner": True, "internal": True},
        "field_added":           {"public": False, "partner": False, "internal": False},
        "field_default_changed": {"public": False, "partner": False, "internal": False},
        "param_removed":         {"public": True, "partner": True, "internal": False},
        "param_type_changed":    {"public": True, "partner": True, "internal": True},
        "param_added":           {"public": False, "partner": False, "internal": False},
        "response_schema_changed": {"public": True, "partner": True, "internal": False},
        "method_changed":        {"public": True, "partner": True, "internal": True},
    }

    if change_type == "field_required_changed":
        old_by_name = {f["name"]: f for f in fields_old}
        new_by_name = {f["name"]: f for f in fields_new}
        old_req = old_by_name.get(field_name, {}).get("required", False)
        new_req = new_by_name.get(field_name, {}).get("required", False)
        if not old_req and new_req:
            return {"public": True, "partner": False, "internal": False}[scope]
        else:
            return False

    if change_type == "param_required_changed":
        old_by_name = {p["name"]: p for p in fields_old}
        new_by_name = {p["name"]: p for p in fields_new}
        old_req = old_by_name.get(field_name, {}).get("required", False)
        new_req = new_by_name.get(field_name, {}).get("required", False)
        if not old_req and new_req:
            return {"public": True, "partner": True, "internal": False}[scope]
        else:
            return False

    return matrix.get(change_type, {}).get(scope, False)

def is_endpoint_deprecated_at_version(endpoint, version_name):
    res_id = endpoint["resource_id"]
    eff = resource_eff_dep.get(res_id)
    if eff is None:
        return False
    dep_at = eff["effective_deprecated_at"]
    ver_date = version_dates.get(version_name)
    if ver_date is None:
        return False
    return ver_date >= dep_at

# === Process all endpoints ===

all_breaking_changes = []
all_migration_steps = []
all_redundancies = []
all_compat_scores = []
all_deprecated_endpoints = []

for ep in endpoints:
    ep_id = ep["endpoint_id"]
    scope = ep["scope"]
    res_id = ep["resource_id"]

    ep_versions_available = []
    for vn in version_order:
        if vn in ep.get("versions", {}):
            ep_versions_available.append(vn)

    ep_breaking_changes = []
    ep_migration_steps_raw = []

    for i in range(len(ep_versions_available) - 1):
        v_from = ep_versions_available[i]
        v_to = ep_versions_available[i + 1]

        spec_from = ep["versions"][v_from]
        spec_to = ep["versions"][v_to]

        changes = []

        field_changes = detect_field_changes(spec_from["fields"], spec_to["fields"])
        for ct, fname in field_changes:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)

            if is_dep_amplified:
                is_brk = True
            else:
                is_brk = is_breaking_by_scope(ct, scope, spec_from["fields"], spec_to["fields"], fname)

            changes.append({
                "change_type": ct,
                "endpoint_id": ep_id,
                "field_or_param": fname,
                "is_breaking": is_brk,
                "scope": scope,
                "version_from": v_from,
                "version_to": v_to
            })

        param_changes = detect_param_changes(spec_from["parameters"], spec_to["parameters"])
        for ct, pname in param_changes:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)

            if is_dep_amplified:
                is_brk = True
            else:
                is_brk = is_breaking_by_scope(ct, scope, spec_from["parameters"], spec_to["parameters"], pname)

            changes.append({
                "change_type": ct,
                "endpoint_id": ep_id,
                "field_or_param": pname,
                "is_breaking": is_brk,
                "scope": scope,
                "version_from": v_from,
                "version_to": v_to
            })

        if spec_from["response_schema"] != spec_to["response_schema"]:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)
            if is_dep_amplified:
                is_brk = True
            else:
                is_brk = is_breaking_by_scope("response_schema_changed", scope, [], [], None)

            changes.append({
                "change_type": "response_schema_changed",
                "endpoint_id": ep_id,
                "field_or_param": None,
                "is_breaking": is_brk,
                "scope": scope,
                "version_from": v_from,
                "version_to": v_to
            })

        if len(changes) > 0:
            breaking_count = sum(1 for c in changes if c["is_breaking"])
            non_breaking_count = sum(1 for c in changes if not c["is_breaking"])

            ep_migration_steps_raw.append({
                "endpoint_id": ep_id,
                "version_from": v_from,
                "version_to": v_to,
                "breaking_count": breaking_count,
                "non_breaking_count": non_breaking_count,
                "total_changes": breaking_count + non_breaking_count
            })

        all_breaking_changes.extend(changes)

    # === TWIST 3: Two-pass redundancy elimination (Rule 5.3-5.4) ===

    def count_direct_changes(ep, v_from, v_to):
        if v_from not in ep["versions"] or v_to not in ep["versions"]:
            return 999999, 0, 0
        spec_f = ep["versions"][v_from]
        spec_t = ep["versions"][v_to]

        fc = detect_field_changes(spec_f["fields"], spec_t["fields"])
        pc = detect_param_changes(spec_f["parameters"], spec_t["parameters"])
        rc = 1 if spec_f["response_schema"] != spec_t["response_schema"] else 0

        total = len(fc) + len(pc) + rc

        brk = 0
        for ct, fname in fc:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)
            if is_dep_amplified:
                brk += 1
            elif is_breaking_by_scope(ct, scope, spec_f["fields"], spec_t["fields"], fname):
                brk += 1

        for ct, pname in pc:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)
            if is_dep_amplified:
                brk += 1
            elif is_breaking_by_scope(ct, scope, spec_f["parameters"], spec_t["parameters"], pname):
                brk += 1

        if rc > 0:
            is_dep_amplified = is_endpoint_deprecated_at_version(ep, v_to)
            if is_dep_amplified:
                brk += 1
            elif is_breaking_by_scope("response_schema_changed", scope, [], [], None):
                brk += 1

        non_brk = total - brk
        return total, brk, non_brk

    redundant_indices = set()
    for i in range(len(ep_migration_steps_raw)):
        step = ep_migration_steps_raw[i]
        if step["breaking_count"] > 0:
            continue
        if i >= len(ep_migration_steps_raw) - 1:
            continue

        next_step = ep_migration_steps_raw[i + 1]
        direct_total, _, _ = count_direct_changes(ep, step["version_from"], next_step["version_to"])
        combined_total = step["total_changes"] + next_step["total_changes"]

        if direct_total < combined_total:
            redundant_indices.add(i)

    final_migration_steps = []
    i = 0
    while i < len(ep_migration_steps_raw):
        step = ep_migration_steps_raw[i]
        if i in redundant_indices:
            next_step = ep_migration_steps_raw[i + 1]

            difficulty_orig = (step["breaking_count"] * scope_weights[scope]) + (step["non_breaking_count"] * 0.5)

            all_redundancies.append({
                "endpoint_id": ep_id,
                "merged_into": {
                    "version_from": step["version_from"],
                    "version_to": next_step["version_to"]
                },
                "original_difficulty": round(difficulty_orig, 2),
                "reason": "zero_breaking_with_cancellation",
                "version_from": step["version_from"],
                "version_to": step["version_to"]
            })

            direct_total, direct_brk, direct_non_brk = count_direct_changes(ep, step["version_from"], next_step["version_to"])
            difficulty_merged = (direct_brk * scope_weights[scope]) + (direct_non_brk * 0.5)

            final_migration_steps.append({
                "breaking_count": direct_brk,
                "endpoint_id": ep_id,
                "merged": True,
                "non_breaking_count": direct_non_brk,
                "total_changes": direct_total,
                "version_from": step["version_from"],
                "version_to": next_step["version_to"]
            })
            i += 2
        else:
            final_migration_steps.append({
                "breaking_count": step["breaking_count"],
                "endpoint_id": ep_id,
                "non_breaking_count": step["non_breaking_count"],
                "total_changes": step["total_changes"],
                "version_from": step["version_from"],
                "version_to": step["version_to"]
            })
            i += 1

    all_migration_steps.extend(final_migration_steps)

    # === Compatibility Scores (Rule 6) ===

    total_breaking = sum(1 for c in all_breaking_changes if c["endpoint_id"] == ep_id and c["is_breaking"])
    total_non_breaking = sum(1 for c in all_breaking_changes if c["endpoint_id"] == ep_id and not c["is_breaking"])

    stability_score = max(0.0, 1.0 - (total_breaking * 0.15) - (total_non_breaking * 0.02))

    any_deprecated = any(is_endpoint_deprecated_at_version(ep, vn) for vn in ep_versions_available)
    if any_deprecated:
        stability_score = stability_score * 0.7

    stability_score = round(stability_score, 4)

    migration_complexity = sum(
        (s["breaking_count"] * scope_weights[scope]) + (s["non_breaking_count"] * 0.5)
        for s in final_migration_steps
    )
    migration_complexity = round(migration_complexity, 2)

    all_compat_scores.append({
        "endpoint_id": ep_id,
        "migration_complexity": migration_complexity,
        "stability_score": stability_score,
        "total_breaking": total_breaking,
        "total_non_breaking": total_non_breaking
    })

    # === Deprecated Endpoints (Rule 8) ===

    if any_deprecated:
        eff = resource_eff_dep.get(res_id)
        affected_versions = sorted([vn for vn in ep_versions_available if is_endpoint_deprecated_at_version(ep, vn)])
        all_deprecated_endpoints.append({
            "deprecation_source": eff["deprecation_source"],
            "effective_deprecated_at": eff["effective_deprecated_at"],
            "effective_sunset_at": eff["effective_sunset_at"],
            "endpoint_id": ep_id,
            "inherited_from": eff["inherited_from"],
            "resource_id": res_id,
            "versions_affected": affected_versions
        })


def sort_key_breaking(c):
    fp = c["field_or_param"] if c["field_or_param"] is not None else ""
    fp_is_null = 0 if c["field_or_param"] is None else 1
    return (c["endpoint_id"], c["version_from"], c["version_to"], c["change_type"], fp_is_null, fp)

all_breaking_changes.sort(key=sort_key_breaking)
all_migration_steps.sort(key=lambda x: (x["endpoint_id"], x["version_from"]))
all_redundancies.sort(key=lambda x: (x["endpoint_id"], x["version_from"]))
all_compat_scores.sort(key=lambda x: x["endpoint_id"])
all_deprecated_endpoints.sort(key=lambda x: x["endpoint_id"])

version_timeline = [{"release_date": v["release_date"], "version_name": v["version_name"]} for v in versions]

total_breaking = sum(1 for c in all_breaking_changes if c["is_breaking"])
total_non_breaking = sum(1 for c in all_breaking_changes if not c["is_breaking"])
total_changes = total_breaking + total_non_breaking

avg_stability = sum(s["stability_score"] for s in all_compat_scores) / len(all_compat_scores) if all_compat_scores else 0.0

summary = {
    "avg_stability_score": round(avg_stability, 4),
    "deprecated_endpoint_count": len(all_deprecated_endpoints),
    "endpoints_analyzed": len(endpoints),
    "total_breaking_changes": total_breaking,
    "total_changes": total_changes,
    "total_migration_steps": len(all_migration_steps),
    "total_non_breaking_changes": total_non_breaking,
    "total_redundant_steps": len(all_redundancies)
}

report = {
    "breaking_changes": all_breaking_changes,
    "compatibility_scores": all_compat_scores,
    "deprecated_endpoints": all_deprecated_endpoints,
    "migration_paths": all_migration_steps,
    "redundancies": all_redundancies,
    "resource_deprecations": resource_deprecations,
    "summary": summary,
    "version_timeline": version_timeline
}

output = json.dumps(report, indent=2, sort_keys=True)
with open(OUTPUT_PATH, "w") as f:
    f.write(output)

print("API compatibility report written to", OUTPUT_PATH)
PYEOF

api-deprecation-cascade-auditor.solution_solve_sh:
#!/bin/bash
set -euo pipefail
cd /app

python3 << 'PYEOF'
import json
from datetime import datetime, timedelta

def load_json(path):
    with open(path) as f:
        return json.load(f)

def parse_date(s):
    if s is None:
        return None
    return datetime.strptime(s, "%Y-%m-%d")

def fmt_date(d):
    return d.strftime("%Y-%m-%d")

def add_days(d, n):
    return d + timedelta(days=n)

services_data = load_json("/app/api_catalog/services.json")
endpoints_data = load_json("/app/api_catalog/endpoints.json")
consumers_data = load_json("/app/api_catalog/consumers.json")
waivers_data = load_json("/app/api_catalog/migration_waivers.json")
config = load_json("/app/api_catalog/config.json")

audit_date = parse_date(config["audit_date"])
weights = config["urgency_weights"]
timeline_window = config["timeline_window_days"]

services = {s["id"]: s for s in services_data["services"]}
endpoints = {e["id"]: e for e in endpoints_data["endpoints"]}
consumers = {c["id"]: c for c in consumers_data["consumers"]}
waivers = waivers_data["waivers"]

# Build waiver lookup: (consumer_id, endpoint_id) -> waiver
waiver_lookup = {}
for w in waivers:
    waiver_lookup[(w["consumer_id"], w["endpoint_id"])] = w

# ============================================================
# Rule 1: Effective Sunset Date Computation
# ============================================================

deprecated_endpoints = {eid: ep for eid, ep in endpoints.items() if ep["deprecated_date"] is not None}

effective_sunsets_map = {}

for eid, ep in deprecated_endpoints.items():
    svc = services[ep["service_id"]]
    policy = svc["deprecation_policy"]
    dep_date = parse_date(ep["deprecated_date"])

    # Step 1a
    if ep["sunset_date"] is not None:
        base_sunset = parse_date(ep["sunset_date"])
    else:
        base_sunset = add_days(dep_date, policy["grace_period_days"])

    # Step 1b
    cap_date = add_days(dep_date, policy["grace_period_days"] + policy["max_sunset_extension_days"])
    capped = False
    effective = base_sunset
    if effective > cap_date:
        effective = cap_date
        capped = True

    effective_sunsets_map[eid] = {
        "endpoint_id": eid,
        "service_id": ep["service_id"],
        "declared_sunset_date": ep["sunset_date"],
        "base_sunset_date": fmt_date(base_sunset),
        "cap_date": fmt_date(cap_date),
        "effective_sunset_date": fmt_date(effective),
        "effective_sunset_dt": effective,
        "capped": capped,
        "deprecated_service_override": False
    }

# Step 1c: deprecated service override
for sid, svc in services.items():
    if svc["status"] == "deprecated":
        svc_endpoints = [eid for eid, ep in deprecated_endpoints.items() if ep["service_id"] == sid]
        if not svc_endpoints:
            continue
        min_sunset = min(effective_sunsets_map[eid]["effective_sunset_dt"] for eid in svc_endpoints)
        for eid in svc_endpoints:
            if effective_sunsets_map[eid]["effective_sunset_dt"] > min_sunset:
                effective_sunsets_map[eid]["effective_sunset_date"] = fmt_date(min_sunset)
                effective_sunsets_map[eid]["effective_sunset_dt"] = min_sunset
                effective_sunsets_map[eid]["deprecated_service_override"] = True
            elif effective_sunsets_map[eid]["effective_sunset_dt"] == min_sunset:
                pass

effective_sunsets = []
for eid in effective_sunsets_map:
    entry = dict(effective_sunsets_map[eid])
    del entry["effective_sunset_dt"]
    effective_sunsets.append(entry)

effective_sunsets.sort(key=lambda x: (x["effective_sunset_date"], x["endpoint_id"]))

def get_effective_sunset_dt(eid):
    return effective_sunsets_map[eid]["effective_sunset_dt"]

def get_cap_date_dt(eid):
    return parse_date(effective_sunsets_map[eid]["cap_date"])

# ============================================================
# Rule 2: Consumer Impact Assessment
# ============================================================

def find_waiver_for_consumer_endpoint(consumer_id, endpoint_id, service_id):
    direct = waiver_lookup.get((consumer_id, endpoint_id))

    svc_wide_waivers = []
    for w in waivers:
        if w["consumer_id"] == consumer_id and w["scope"] == "service_wide":
            w_ep = endpoints[w["endpoint_id"]]
            if w_ep["service_id"] == service_id:
                svc_wide_waivers.append(w)

    best_waiver = None
    best_ext = 0

    if direct:
        best_waiver = direct
        best_ext = direct["extension_days"]

    for sw in svc_wide_waivers:
        if sw["extension_days"] > best_ext:
            best_waiver = sw
            best_ext = sw["extension_days"]

    return best_waiver, best_ext

consumer_impact_details = []

for con in consumers_data["consumers"]:
    for dep in con["dependencies"]:
        ep_id = dep["endpoint_id"]
        if ep_id not in deprecated_endpoints:
            continue

        ep = endpoints[ep_id]
        eff_sunset = get_effective_sunset_dt(ep_id)
        cap_dt = get_cap_date_dt(ep_id)

        waiver, ext_days = find_waiver_for_consumer_endpoint(con["id"], ep_id, ep["service_id"])

        waiver_adjusted = None
        waiver_id = None
        waiver_scope = None
        if waiver and ext_days > 0:
            adjusted = min(add_days(eff_sunset, ext_days), add_days(cap_dt, ext_days))
            waiver_adjusted = fmt_date(adjusted)
            waiver_id = waiver["id"]
            waiver_scope = waiver["scope"]
            days_rem = (adjusted - audit_date).days
        else:
            days_rem = (eff_sunset - audit_date).days

        # Classification
        mig_status = dep["migration_status"]
        if mig_status == "completed":
            classification = "migrated"
        elif mig_status == "in_progress":
            if days_rem > 30:
                classification = "on_track"
            elif days_rem > 0:
                classification = "at_risk"
            else:
                classification = "overdue"
        else:  # not_started
            if days_rem > 60:
                classification = "pending"
            elif days_rem > 0:
                classification = "urgent"
            else:
                classification = "overdue"

        # Successor check
        successor_deprecated = False
        successor_sunset = None
        target_id = dep["migration_target_id"]
        if target_id and target_id in deprecated_endpoints:
            successor_deprecated = True
            successor_sunset = effective_sunsets_map[target_id]["effective_sunset_date"]

        consumer_impact_details.append({
            "breaking_changes_count": len(ep["breaking_changes"]),
            "consumer_id": con["id"],
            "consumer_name": con["name"],
            "consumer_tier": con["tier"],
            "days_remaining": days_rem,
            "effective_sunset_date": fmt_date(eff_sunset),
            "endpoint_id": ep_id,
            "migration_classification": classification,
            "successor_also_deprecated": successor_deprecated,
            "successor_sunset_date": successor_sunset,
            "waiver_adjusted_sunset": waiver_adjusted,
            "waiver_id": waiver_id,
            "waiver_scope": waiver_scope
        })

consumer_impact_details.sort(key=lambda x: (x["consumer_id"], x["endpoint_id"]))

# Build lookup for impact details
impact_lookup = {}
for ci in consumer_impact_details:
    impact_lookup[(ci["consumer_id"], ci["endpoint_id"])] = ci

# ============================================================
# Rule 5: Phantom Deprecation Detection (before cascade/urgency)
# ============================================================

phantom_endpoints = set()
phantom_deprecations = []

for eid in deprecated_endpoints:
    ep = endpoints[eid]
    consumer_deps = []
    for con in consumers_data["consumers"]:
        for dep in con["dependencies"]:
            if dep["endpoint_id"] == eid:
                consumer_deps.append((con["id"], dep["migration_status"]))

    if not consumer_deps:
        phantom_endpoints.add(eid)
        phantom_deprecations.append({
            "endpoint_id": eid,
            "service_id": ep["service_id"],
            "effective_sunset_date": effective_sunsets_map[eid]["effective_sunset_date"],
            "reason": "no_consumers"
        })
    elif all(ms == "completed" for _, ms in consumer_deps):
        phantom_endpoints.add(eid)
        phantom_deprecations.append({
            "endpoint_id": eid,
            "service_id": ep["service_id"],
            "effective_sunset_date": effective_sunsets_map[eid]["effective_sunset_date"],
            "reason": "all_consumers_migrated"
        })

phantom_deprecations.sort(key=lambda x: x["endpoint_id"])

# ============================================================
# Rule 3: Cascade Chain Construction (after phantom detection)
# ============================================================

cascade_chains = []

for eid in deprecated_endpoints:
    if eid in phantom_endpoints:
        continue

    ep = endpoints[eid]

    # Build successor chain
    successor_chain = [eid]
    current = eid
    depth_limit = config["cascade_depth_limit"]
    while len(successor_chain) < depth_limit:
        curr_ep = endpoints[current]
        succ = curr_ep.get("successor_id")
        if succ and succ in deprecated_endpoints:
            successor_chain.append(succ)
            current = succ
        else:
            break

    # Find affected consumers
    affected = []
    for con in consumers_data["consumers"]:
        for dep in con["dependencies"]:
            if dep["endpoint_id"] == eid and dep["migration_status"] != "completed":
                # cross-service conflicts
                cross = []
                for other_dep in con["dependencies"]:
                    other_eid = other_dep["endpoint_id"]
                    if other_eid == eid:
                        continue
                    if other_dep["migration_status"] == "completed":
                        continue
                    if other_eid not in deprecated_endpoints:
                        continue
                    if other_eid in phantom_endpoints:
                        continue
                    other_ep = endpoints[other_eid]
                    if other_ep["service_id"] != ep["service_id"]:
                        cross.append(other_eid)

                cross.sort()
                ci = impact_lookup.get((con["id"], eid))
                classification = ci["migration_classification"] if ci else "unknown"

                affected.append({
                    "consumer_id": con["id"],
                    "consumer_tier": con["tier"],
                    "cross_service_conflicts": cross,
                    "migration_classification": classification
                })

    if not affected:
        continue

    affected.sort(key=lambda x: x["consumer_id"])

    total_crit = sum(1 for a in affected if a["consumer_tier"] == "critical")
    total_std = sum(1 for a in affected if a["consumer_tier"] == "standard")
    total_int = sum(1 for a in affected if a["consumer_tier"] == "internal")

    cascade_chains.append({
        "affected_consumers": affected,
        "depth": len(successor_chain),
        "root_effective_sunset": effective_sunsets_map[eid]["effective_sunset_date"],
        "root_endpoint_id": eid,
        "root_service_id": ep["service_id"],
        "successor_chain": successor_chain,
        "total_affected_critical": total_crit,
        "total_affected_internal": total_int,
        "total_affected_standard": total_std
    })

cascade_chains.sort(key=lambda x: (x["root_effective_sunset"], x["root_endpoint_id"]))

# ============================================================
# Rule 4: Migration Urgency Scoring (after phantom removal)
# ============================================================

migration_urgency_scores = []

for ci in consumer_impact_details:
    if ci["migration_classification"] == "migrated":
        continue
    if ci["endpoint_id"] in phantom_endpoints:
        continue

    ep = endpoints[ci["endpoint_id"]]
    con = consumers[ci["consumer_id"]]
    dep = None
    for d in con["dependencies"]:
        if d["endpoint_id"] == ci["endpoint_id"]:
            dep = d
            break

    days_rem = ci["days_remaining"]

    # Step 4a
    if days_rem < 0:
        raw_base = (180 - days_rem) * weights["days_until_sunset"]
    else:
        raw_base = max(0, (180 - days_rem)) * weights["days_until_sunset"]
    base_score = round(raw_base, 2)

    # Step 4b
    tier_mult = weights["consumer_tier_multiplier"][con["tier"]]

    # Step 4c
    usage_mult = weights["usage_frequency_multiplier"][dep["usage_frequency"]]

    # Step 4d
    bc_count = len(ep["breaking_changes"])
    breaking_penalty = weights["breaking_change_penalty"] * bc_count

    # Step 4e & 4f
    successor_penalty = 0.0
    if ep["successor_id"] is None and dep["migration_target_id"] is None:
        successor_penalty = weights["no_successor_penalty"]
    elif ci["successor_also_deprecated"]:
        successor_penalty = weights["no_successor_penalty"] * 0.5

    final_score = round(base_score * tier_mult * usage_mult + breaking_penalty + successor_penalty, 2)

    if final_score >= 200:
        bucket = "critical"
    elif final_score >= 100:
        bucket = "high"
    elif final_score >= 50:
        bucket = "medium"
    else:
        bucket = "low"

    migration_urgency_scores.append({
        "base_score": base_score,
        "breaking_change_penalty": breaking_penalty,
        "consumer_id": ci["consumer_id"],
        "days_remaining": days_rem,
        "endpoint_id": ci["endpoint_id"],
        "final_score": final_score,
        "priority_bucket": bucket,
        "successor_penalty": successor_penalty,
        "tier_multiplier": tier_mult,
        "usage_multiplier": usage_mult
    })

migration_urgency_scores.sort(key=lambda x: (-x["final_score"], x["consumer_id"], x["endpoint_id"]))

# ============================================================
# Rule 6: Counterfactual Waiver Analysis
# ============================================================

CLASS_ORDER = {"migrated": 0, "on_track": 1, "at_risk": 2, "pending": 3, "urgent": 4, "overdue": 5}

def classify(mig_status, days_rem):
    if mig_status == "completed":
        return "migrated"
    elif mig_status == "in_progress":
        if days_rem > 30:
            return "on_track"
        elif days_rem > 0:
            return "at_risk"
        else:
            return "overdue"
    else:
        if days_rem > 60:
            return "pending"
        elif days_rem > 0:
            return "urgent"
        else:
            return "overdue"

def compute_score_for_pair(consumer_id, endpoint_id, days_rem, classification):
    if classification == "migrated":
        return 0.0
    if endpoint_id in phantom_endpoints:
        return 0.0

    ep = endpoints[endpoint_id]
    con = consumers[consumer_id]
    dep = None
    for d in con["dependencies"]:
        if d["endpoint_id"] == endpoint_id:
            dep = d
            break
    if dep is None:
        return 0.0

    if days_rem < 0:
        raw_base = (180 - days_rem) * weights["days_until_sunset"]
    else:
        raw_base = max(0, (180 - days_rem)) * weights["days_until_sunset"]
    base_score = round(raw_base, 2)

    tier_mult = weights["consumer_tier_multiplier"][con["tier"]]
    usage_mult = weights["usage_frequency_multiplier"][dep["usage_frequency"]]

    bc_count = len(ep["breaking_changes"])
    breaking_penalty = weights["breaking_change_penalty"] * bc_count

    successor_penalty = 0.0
    target_id = dep["migration_target_id"]
    if ep["successor_id"] is None and target_id is None:
        successor_penalty = weights["no_successor_penalty"]
    elif target_id and target_id in deprecated_endpoints:
        successor_penalty = weights["no_successor_penalty"] * 0.5

    return round(base_score * tier_mult * usage_mult + breaking_penalty + successor_penalty, 2)

counterfactual_analysis = []

for w in waivers:
    wid = w["id"]
    con_id = w["consumer_id"]
    ep_id = w["endpoint_id"]
    scope = w["scope"]
    ext_days = w["extension_days"]

    ep = endpoints[ep_id]
    svc_id = ep["service_id"]

    # Determine affected pairs
    affected_ep_ids = []
    if scope == "endpoint_only":
        affected_ep_ids = [ep_id]
    else:  # service_wide
        con = consumers[con_id]
        for dep in con["dependencies"]:
            dep_ep = endpoints[dep["endpoint_id"]]
            if dep_ep["service_id"] == svc_id and dep["endpoint_id"] in deprecated_endpoints:
                affected_ep_ids.append(dep["endpoint_id"])

    affected_pairs = []
    for aep_id in sorted(affected_ep_ids):
        ci = impact_lookup.get((con_id, aep_id))
        if ci is None:
            continue

        orig_class = ci["migration_classification"]
        orig_days = ci["days_remaining"]
        orig_score_val = 0.0
        for mus in migration_urgency_scores:
            if mus["consumer_id"] == con_id and mus["endpoint_id"] == aep_id:
                orig_score_val = mus["final_score"]
                break
        if orig_class == "migrated":
            orig_score_val = 0.0

        # Counterfactual: compute without this waiver
        eff_sunset = get_effective_sunset_dt(aep_id)

        # Check if there's ANOTHER waiver that would still apply
        other_waiver, other_ext = None, 0
        for ow in waivers:
            if ow["id"] == wid:
                continue
            if ow["consumer_id"] == con_id:
                if ow["scope"] == "endpoint_only" and ow["endpoint_id"] == aep_id:
                    if ow["extension_days"] > other_ext:
                        other_waiver = ow
                        other_ext = ow["extension_days"]
                elif ow["scope"] == "service_wide":
                    ow_ep = endpoints[ow["endpoint_id"]]
                    if ow_ep["service_id"] == svc_id:
                        if ow["extension_days"] > other_ext:
                            other_waiver = ow
                            other_ext = ow["extension_days"]

        cap_dt = get_cap_date_dt(aep_id)
        if other_ext > 0:
            cf_adjusted = min(add_days(eff_sunset, other_ext), add_days(cap_dt, other_ext))
            cf_days = (cf_adjusted - audit_date).days
        else:
            cf_days = (eff_sunset - audit_date).days

        con_obj = consumers[con_id]
        dep_obj = None
        for d in con_obj["dependencies"]:
            if d["endpoint_id"] == aep_id:
                dep_obj = d
                break

        cf_class = classify(dep_obj["migration_status"], cf_days)
        cf_score = compute_score_for_pair(con_id, aep_id, cf_days, cf_class)

        worsened = CLASS_ORDER.get(cf_class, 0) > CLASS_ORDER.get(orig_class, 0)

        affected_pairs.append({
            "classification_worsened": worsened,
            "counterfactual_classification": cf_class,
            "counterfactual_days_remaining": cf_days,
            "counterfactual_score": cf_score,
            "endpoint_id": aep_id,
            "original_classification": orig_class,
            "original_days_remaining": orig_days,
            "original_score": orig_score_val,
            "score_delta": round(cf_score - orig_score_val, 2)
        })

    affected_pairs.sort(key=lambda x: x["endpoint_id"])
    is_impactful = any(ap["classification_worsened"] for ap in affected_pairs)
    total_delta = round(sum(ap["score_delta"] for ap in affected_pairs), 2)

    counterfactual_analysis.append({
        "affected_pairs": affected_pairs,
        "consumer_id": con_id,
        "is_impactful": is_impactful,
        "scope": scope,
        "total_score_delta": total_delta,
        "waiver_id": wid
    })

counterfactual_analysis.sort(key=lambda x: x["waiver_id"])

# ============================================================
# Rule 7: Sunset Timeline
# ============================================================

from collections import defaultdict

def month_key(d):
    return d.strftime("%Y-%m")

# Determine which consumers break in which month
consumer_first_break = {}

# For each consumer, find the earliest month they lose an endpoint
for ci in consumer_impact_details:
    if ci["migration_classification"] == "migrated":
        continue
    eid = ci["endpoint_id"]
    con_id = ci["consumer_id"]

    if ci["waiver_adjusted_sunset"]:
        sunset_dt = parse_date(ci["waiver_adjusted_sunset"])
    else:
        sunset_dt = get_effective_sunset_dt(eid)

    mk = month_key(sunset_dt)

    if con_id not in consumer_first_break or mk < consumer_first_break[con_id]:
        consumer_first_break[con_id] = mk

# Group endpoints by sunset month
month_endpoints = defaultdict(set)
for eid in deprecated_endpoints:
    sunset_dt = get_effective_sunset_dt(eid)
    mk = month_key(sunset_dt)
    month_endpoints[mk].add(eid)

# Build timeline
timeline_months = sorted(month_endpoints.keys())
cumulative_broken = 0
seen_broken = set()

sunset_timeline = []
for mk in timeline_months:
    ep_list = sorted(month_endpoints[mk])
    all_phantom = all(eid in phantom_endpoints for eid in ep_list)

    new_broken = []
    for con_id, first_mk in consumer_first_break.items():
        if first_mk == mk and con_id not in seen_broken:
            new_broken.append(con_id)
            seen_broken.add(con_id)

    new_broken.sort()
    cumulative_broken += len(new_broken)

    # Severity
    if all_phantom or not new_broken:
        severity = "info"
    else:
        max_tier = "internal"
        for con_id in new_broken:
            tier = consumers[con_id]["tier"]
            if tier == "critical":
                max_tier = "critical"
                break
            elif tier == "standard" and max_tier != "critical":
                max_tier = "standard"
        if max_tier == "critical":
            severity = "critical"
        elif max_tier == "standard":
            severity = "warning"
        else:
            severity = "info"

    sunset_timeline.append({
        "cumulative_broken_consumers": cumulative_broken,
        "endpoints_sunsetting": ep_list,
        "month": mk,
        "new_broken_consumers": new_broken,
        "phantom": all_phantom,
        "severity": severity
    })

# ============================================================
# Rule 8: Summary
# ============================================================

total_deprecated = len(deprecated_endpoints)
total_past_due = sum(1 for eid in deprecated_endpoints if get_effective_sunset_dt(eid) < audit_date)
total_phantoms = len(phantom_endpoints)
total_waivers = len(waivers)
total_impactful = sum(1 for ca in counterfactual_analysis if ca["is_impactful"])

risk_counts = {"migrated": 0, "on_track": 0, "at_risk": 0, "pending": 0, "urgent": 0, "overdue": 0}
for ci in consumer_impact_details:
    risk_counts[ci["migration_classification"]] += 1

priority_counts = {"critical": 0, "high": 0, "medium": 0, "low": 0}
for mus in migration_urgency_scores:
    priority_counts[mus["priority_bucket"]] += 1

highest_consumer = None
highest_score = 0.0
for mus in migration_urgency_scores:
    if mus["final_score"] > highest_score or (mus["final_score"] == highest_score and (highest_consumer is None or mus["consumer_id"] < highest_consumer)):
        highest_score = mus["final_score"]
        highest_consumer = mus["consumer_id"]

crit_at_risk = sum(1 for ci in consumer_impact_details
                   if ci["consumer_tier"] == "critical"
                   and ci["migration_classification"] in ("at_risk", "urgent", "overdue"))

# Services where every endpoint version is deprecated
svc_all_deprecated = []
svc_endpoint_counts = defaultdict(int)
svc_deprecated_counts = defaultdict(int)
for eid, ep in endpoints.items():
    svc_endpoint_counts[ep["service_id"]] += 1
    if ep["deprecated_date"] is not None:
        svc_deprecated_counts[ep["service_id"]] += 1

for sid in sorted(svc_endpoint_counts.keys()):
    if svc_endpoint_counts[sid] == svc_deprecated_counts[sid]:
        svc_all_deprecated.append(sid)

summary = {
    "audit_date": config["audit_date"],
    "consumers_by_risk": risk_counts,
    "critical_tier_at_risk_count": crit_at_risk,
    "highest_urgency_consumer": highest_consumer,
    "highest_urgency_score": highest_score,
    "priority_distribution": priority_counts,
    "services_with_all_versions_deprecated": svc_all_deprecated,
    "total_active_waivers": total_waivers,
    "total_deprecated_endpoints": total_deprecated,
    "total_impactful_waivers": total_impactful,
    "total_phantom_deprecations": total_phantoms,
    "total_sunset_past_due": total_past_due
}

# ============================================================
# Assemble report
# ============================================================

report = {
    "cascade_chains": cascade_chains,
    "consumer_impact_details": consumer_impact_details,
    "counterfactual_analysis": counterfactual_analysis,
    "effective_sunsets": effective_sunsets,
    "migration_urgency_scores": migration_urgency_scores,
    "phantom_deprecations": phantom_deprecations,
    "summary": summary,
    "sunset_timeline": sunset_timeline
}

output = json.dumps(report, indent=2, sort_keys=True)
with open("/app/api_catalog_report.json", "w") as f:
    f.write(output)

print("API deprecation cascade audit complete. Report written to /app/api_catalog_report.json")
