import json
import math
import os

DATA_DIR = "/app/cgroup_hierarchy"

def load_json(filename):
    with open(os.path.join(DATA_DIR, filename)) as f:
        return json.load(f)

topology = load_json("topology.json")
processes = load_json("processes.json")
pressure_events = load_json("pressure_events.json")
weight_policies = load_json("weight_policies.json")
oom_config = load_json("oom_config.json")
config = load_json("config.json")

nodes = topology["nodes"]
root = topology["root"]

# Build full node map including root
all_nodes = {"root": root}
all_nodes.update(nodes)

# Compute depth for each node
def compute_depth(name):
    if name == "root":
        return 0
    parent = all_nodes[name]["parent"]
    return 1 + compute_depth(parent)

depths = {}
for name in all_nodes:
    depths[name] = compute_depth(name)

# Get all ancestors (excluding self)
def get_ancestors(name):
    ancestors = []
    current = name
    while current != "root":
        parent = all_nodes[current]["parent"]
        ancestors.append(parent)
        current = parent
    return ancestors

# Get effective limit for any cgroup
def get_effective_cpu(name):
    my_limit = all_nodes[name]["cpu_max_us"]
    ancestors = get_ancestors(name)
    min_limit = my_limit
    for a in ancestors:
        min_limit = min(min_limit, all_nodes[a]["cpu_max_us"])
    return min_limit

def get_effective_memory(name):
    my_limit = all_nodes[name]["memory_max_bytes"]
    ancestors = get_ancestors(name)
    min_limit = my_limit
    for a in ancestors:
        min_limit = min(min_limit, all_nodes[a]["memory_max_bytes"])
    return min_limit

def get_effective_io_weight(name):
    my_weight = all_nodes[name]["io_weight"]
    min_weight = my_weight
    ancestors = get_ancestors(name)
    for a in ancestors:
        min_weight = min(min_weight, all_nodes[a]["io_weight"])
    return min_weight

def get_capping_ancestor_cpu(name):
    my_limit = all_nodes[name]["cpu_max_us"]
    effective = get_effective_cpu(name)
    if effective >= my_limit:
        return None
    # Find lowest ancestor that imposes the cap
    ancestors = get_ancestors(name)
    # ancestors are in order from parent to root
    capper = None
    for a in ancestors:
        if all_nodes[a]["cpu_max_us"] <= effective:
            capper = a
            break
    return capper

def get_capping_ancestor_memory(name):
    my_limit = all_nodes[name]["memory_max_bytes"]
    effective = get_effective_memory(name)
    if effective >= my_limit:
        return None
    ancestors = get_ancestors(name)
    capper = None
    for a in ancestors:
        if all_nodes[a]["memory_max_bytes"] <= effective:
            capper = a
            break
    return capper

# Identify leaf cgroups
leaf_cgroups = [name for name in all_nodes if all_nodes[name].get("children", []) == []]

# Rule 1: Effective Limits
effective_limits = []
for name in leaf_cgroups:
    entry = {
        "cgroup": name,
        "declared_cpu_max_us": all_nodes[name]["cpu_max_us"],
        "effective_cpu_max_us": get_effective_cpu(name),
        "declared_memory_max_bytes": all_nodes[name]["memory_max_bytes"],
        "effective_memory_max_bytes": get_effective_memory(name),
        "declared_io_weight": all_nodes[name]["io_weight"],
        "effective_io_weight": get_effective_io_weight(name),
        "depth": depths[name],
        "capped_by_cpu": get_capping_ancestor_cpu(name),
        "capped_by_memory": get_capping_ancestor_memory(name)
    }
    effective_limits.append(entry)

effective_limits.sort(key=lambda x: x["cgroup"])

# Rule 2: CPU Weight Distribution
def get_children(cgroup_name):
    return all_nodes[cgroup_name].get("children", [])

def distribute_cpu(target, mode, scope, priority_boost):
    children = get_children(target)
    if not children:
        return []

    parent_effective_cpu = get_effective_cpu(target)
    allocations = []

    if mode == "weighted":
        total_weight = sum(all_nodes[c]["cpu_weight"] + priority_boost for c in children)
        for c in children:
            w = all_nodes[c]["cpu_weight"]
            ew = w + priority_boost
            allocated = math.floor(parent_effective_cpu * (ew / total_weight))
            allocations.append({
                "cgroup": c,
                "weight": w,
                "effective_weight": ew,
                "allocated_cpu_us": allocated
            })
    elif mode == "equal":
        per_child = math.floor(parent_effective_cpu / len(children))
        for c in children:
            w = all_nodes[c]["cpu_weight"]
            allocations.append({
                "cgroup": c,
                "weight": w,
                "effective_weight": w,
                "allocated_cpu_us": per_child
            })

    if scope == "full_subtree":
        sub_allocations = []
        for alloc in allocations:
            child_name = alloc["cgroup"]
            child_children = get_children(child_name)
            if child_children:
                child_distributable = alloc["allocated_cpu_us"]
                if mode == "weighted":
                    child_total_weight = sum(all_nodes[gc]["cpu_weight"] + priority_boost for gc in child_children)
                    for gc in child_children:
                        gcw = all_nodes[gc]["cpu_weight"]
                        gcew = gcw + priority_boost
                        gc_allocated = math.floor(child_distributable * (gcew / child_total_weight))
                        sub_allocations.append({
                            "cgroup": gc,
                            "weight": gcw,
                            "effective_weight": gcew,
                            "allocated_cpu_us": gc_allocated
                        })
                        # Recurse further
                        gc_children = get_children(gc)
                        if gc_children:
                            gc_distributable = gc_allocated
                            gc_total_weight = sum(all_nodes[ggc]["cpu_weight"] + priority_boost for ggc in gc_children)
                            for ggc in gc_children:
                                ggcw = all_nodes[ggc]["cpu_weight"]
                                ggcew = ggcw + priority_boost
                                ggc_allocated = math.floor(gc_distributable * (ggcew / gc_total_weight))
                                sub_allocations.append({
                                    "cgroup": ggc,
                                    "weight": ggcw,
                                    "effective_weight": ggcew,
                                    "allocated_cpu_us": ggc_allocated
                                })
                elif mode == "equal":
                    per_gc = math.floor(child_distributable / len(child_children))
                    for gc in child_children:
                        gcw = all_nodes[gc]["cpu_weight"]
                        sub_allocations.append({
                            "cgroup": gc,
                            "weight": gcw,
                            "effective_weight": gcw,
                            "allocated_cpu_us": per_gc
                        })
                        gc_children = get_children(gc)
                        if gc_children:
                            per_ggc = math.floor(per_gc / len(gc_children))
                            for ggc in gc_children:
                                ggcw = all_nodes[ggc]["cpu_weight"]
                                sub_allocations.append({
                                    "cgroup": ggc,
                                    "weight": ggcw,
                                    "effective_weight": ggcw,
                                    "allocated_cpu_us": per_ggc
                                })
        allocations.extend(sub_allocations)

    allocations.sort(key=lambda x: x["cgroup"])
    return allocations

cpu_distribution = []
for pol in weight_policies["policies"]:
    if pol["resource"] != "cpu":
        continue
    allocs = distribute_cpu(pol["target_cgroup"], pol["distribution_mode"], pol["scope"], pol["priority_boost"])
    cpu_distribution.append({
        "policy_id": pol["id"],
        "target_cgroup": pol["target_cgroup"],
        "mode": pol["distribution_mode"],
        "scope": pol["scope"],
        "allocations": allocs
    })

cpu_distribution.sort(key=lambda x: x["policy_id"])

# Rule 3: Overcommit Analysis
non_leaf_cgroups = [name for name in all_nodes if all_nodes[name].get("children", []) != []]

overcommit_analysis = []
params = config["audit_parameters"]

for name in non_leaf_cgroups:
    children = get_children(name)
    parent_eff_cpu = get_effective_cpu(name)
    parent_eff_mem = get_effective_memory(name)

    sum_child_cpu = sum(all_nodes[c]["cpu_max_us"] for c in children)
    sum_child_mem = sum(all_nodes[c]["memory_max_bytes"] for c in children)

    cpu_ratio = sum_child_cpu / parent_eff_cpu
    mem_ratio = sum_child_mem / parent_eff_mem

    if cpu_ratio < params["cpu_overcommit_warning_ratio"]:
        cpu_status = "ok"
    elif cpu_ratio < params["cpu_overcommit_critical_ratio"]:
        cpu_status = "warning"
    else:
        cpu_status = "critical"

    if mem_ratio < params["memory_overcommit_warning_ratio"]:
        mem_status = "ok"
    elif mem_ratio < params["memory_overcommit_critical_ratio"]:
        mem_status = "critical"
    else:
        mem_status = "critical"

    # Re-check memory thresholds correctly
    if mem_ratio < params["memory_overcommit_warning_ratio"]:
        mem_status = "ok"
    elif mem_ratio < params["memory_overcommit_critical_ratio"]:
        mem_status = "warning"
    else:
        mem_status = "critical"

    # Build detail
    cpu_bad = cpu_status in ("warning", "critical")
    mem_bad = mem_status in ("warning", "critical")

    if not cpu_bad and not mem_bad:
        detail = "No overcommit detected"
    elif cpu_bad and mem_bad:
        detail = f"CPU overcommit {cpu_ratio:.2f}x ({cpu_status}); Memory overcommit {mem_ratio:.2f}x ({mem_status})"
    elif cpu_bad:
        detail = f"CPU overcommit {cpu_ratio:.2f}x ({cpu_status})"
    else:
        detail = f"Memory overcommit {mem_ratio:.2f}x ({mem_status})"

    overcommit_analysis.append({
        "cgroup": name,
        "cpu_overcommit_ratio": round(cpu_ratio, 4),
        "cpu_status": cpu_status,
        "memory_overcommit_ratio": round(mem_ratio, 4),
        "memory_status": mem_status,
        "children_count": len(children),
        "detail": detail
    })

overcommit_analysis.sort(key=lambda x: x["cgroup"])

# Rule 4: Pressure Responses
def get_leaf_descendants(name):
    children = get_children(name)
    if not children:
        return [name]
    leaves = []
    for c in children:
        leaves.extend(get_leaf_descendants(c))
    return leaves

pressure_responses = []
for evt in pressure_events["events"]:
    evt_type = evt["type"]
    level = evt["level"]
    cgroup = evt["cgroup"]
    scope = evt["scope"]

    if evt_type == "memory_pressure":
        if level == "critical":
            response = "oom_kill"
            detail = f"OOM kill triggered in {cgroup}"
        elif level == "high":
            response = "reclaim"
            detail = f"Memory reclaim initiated in {cgroup}, usage={evt['trigger_usage_bytes']}B"
        else:
            response = "throttle"
            detail = f"Memory throttle applied to {cgroup}"
    elif evt_type == "cpu_throttle":
        response = "throttle_propagate"
        if scope == "subtree":
            affected = get_leaf_descendants(cgroup)
        else:
            affected = get_leaf_descendants(cgroup) if not get_children(cgroup) else [cgroup]
            if get_children(cgroup) and scope == "local":
                affected = [cgroup]
        n = len(affected) if scope == "subtree" else 1
        # For subtree scope, count all leaf descendants
        if scope == "subtree":
            affected_list = get_leaf_descendants(cgroup)
            # Include the target itself if it's a leaf
            n = len(affected_list)
        else:
            affected_list = [cgroup] if get_children(cgroup) else [cgroup]
            n = len(affected_list)
        detail = f"CPU throttle propagated to {n} cgroups, duration={evt['throttle_duration_us']}us"
    elif evt_type == "io_latency":
        if level == "high":
            response = "io_priority_boost"
            detail = f"IO priority boosted by 20 for {cgroup}"
        else:
            response = "io_monitor"
            detail = f"IO latency monitoring enabled for {cgroup}"

    # Compute affected_cgroups
    if evt_type == "cpu_throttle":
        if scope == "subtree":
            affected_cgroups = sorted(get_leaf_descendants(cgroup))
        else:
            if not get_children(cgroup):
                affected_cgroups = [cgroup]
            else:
                affected_cgroups = [cgroup]
    elif evt_type == "memory_pressure" or evt_type == "io_latency":
        if scope == "subtree":
            affected_cgroups = sorted(get_leaf_descendants(cgroup))
        else:
            if not get_children(cgroup):
                affected_cgroups = [cgroup]
            else:
                affected_cgroups = [cgroup]

    pressure_responses.append({
        "event_id": evt["id"],
        "timestamp_ms": evt["timestamp_ms"],
        "type": evt_type,
        "cgroup": cgroup,
        "level": level,
        "response": response,
        "affected_cgroups": affected_cgroups,
        "detail": detail
    })

pressure_responses.sort(key=lambda x: (x["timestamp_ms"], x["event_id"]))

# Rule 5: OOM Kill Simulation
oom_kill_log = []
killed_pids = set()
killed_processes_info = []

for evt in pressure_events["events"]:
    if evt["type"] != "memory_pressure" or evt["level"] != "critical":
        continue

    cgroup = evt["cgroup"]
    scope = evt["scope"]

    # Gather processes
    if scope == "subtree":
        target_cgroups = set()
        target_cgroups.add(cgroup)
        # Add all descendants
        def add_descendants(name):
            for c in get_children(name):
                target_cgroups.add(c)
                add_descendants(c)
        add_descendants(cgroup)
    else:
        target_cgroups = {cgroup}

    candidates = []
    for proc in processes["processes"]:
        if proc["cgroup"] in target_cgroups:
            depth = depths[proc["cgroup"]]
            computed_score = (proc["oom_score_adj"] +
                           oom_config["oom_score_calculation"]["memory_pressure_bonus"] +
                           depth * oom_config["oom_score_calculation"]["nested_depth_bonus_per_level"])
            candidates.append({
                "pid": proc["pid"],
                "name": proc["name"],
                "cgroup": proc["cgroup"],
                "oom_score_adj": proc["oom_score_adj"],
                "computed_oom_score": computed_score,
                "memory_usage_bytes": proc["memory_usage_bytes"]
            })

    # Filter protected
    threshold = oom_config["protected_oom_score_threshold"]
    protected = [c for c in candidates if c["computed_oom_score"] < threshold]
    killable = [c for c in candidates if c["computed_oom_score"] >= threshold]

    # Sort by computed score desc, then pid asc
    killable.sort(key=lambda x: (-x["computed_oom_score"], x["pid"]))

    # Kill up to max
    max_kills = oom_config["max_kills_per_event"]
    kills = []
    for k in killable[:max_kills]:
        kills.append({
            "pid": k["pid"],
            "name": k["name"],
            "cgroup": k["cgroup"],
            "oom_score_adj": k["oom_score_adj"],
            "computed_oom_score": k["computed_oom_score"],
            "memory_freed_bytes": k["memory_usage_bytes"]
        })
        killed_pids.add(k["pid"])
        killed_processes_info.append(k)

    total_freed = sum(k["memory_freed_bytes"] for k in kills)

    oom_kill_log.append({
        "event_id": evt["id"],
        "timestamp_ms": evt["timestamp_ms"],
        "cgroup": cgroup,
        "kills": kills,
        "total_memory_freed_bytes": total_freed,
        "processes_considered": len(candidates),
        "processes_protected": len(protected)
    })

oom_kill_log.sort(key=lambda x: x["timestamp_ms"])

# Rule 6: Post-OOM State
# Build per-cgroup process lists
cgroup_processes = {}
for name in leaf_cgroups:
    cgroup_processes[name] = []

for proc in processes["processes"]:
    cg = proc["cgroup"]
    if cg in cgroup_processes:
        cgroup_processes[cg].append(proc)

post_oom_state = []
for name in leaf_cgroups:
    procs = cgroup_processes[name]
    original_usage = sum(p["memory_usage_bytes"] for p in procs)

    killed_from_this = [p for p in killed_processes_info if p["cgroup"] == name]
    killed_pids_this = [p["pid"] for p in killed_from_this]

    remaining_procs = [p for p in procs if p["pid"] not in killed_pids]
    post_kill_usage = sum(p["memory_usage_bytes"] for p in remaining_procs)

    eff_limit = get_effective_memory(name)
    reclaimed = original_usage - post_kill_usage
    util_ratio = post_kill_usage / eff_limit if eff_limit > 0 else 0.0

    if killed_pids_this:
        if post_kill_usage <= eff_limit:
            status = "resolved"
        else:
            status = "unresolved"
    else:
        status = "unaffected"

    post_oom_state.append({
        "cgroup": name,
        "original_usage_bytes": original_usage,
        "post_kill_usage_bytes": post_kill_usage,
        "effective_limit_bytes": eff_limit,
        "status": status,
        "killed_pids": sorted(killed_pids_this),
        "memory_reclaimed_bytes": reclaimed,
        "utilization_ratio": round(util_ratio, 4)
    })

post_oom_state.sort(key=lambda x: x["cgroup"])

# Rule 7: Throttle Chains
throttle_chains = []

for evt in pressure_events["events"]:
    if evt["type"] != "cpu_throttle":
        continue

    cgroup = evt["cgroup"]
    scope = evt["scope"]
    throttle_us = evt["throttle_duration_us"]
    decay = config["audit_parameters"]["throttle_propagation_decay"]

    chain = []

    # The origin cgroup itself
    if cgroup in leaf_cgroups:
        eff_cpu = get_effective_cpu(cgroup)
    else:
        eff_cpu = get_effective_cpu(cgroup)

    severity = throttle_us / eff_cpu if eff_cpu > 0 else 0.0
    if severity < 0.3:
        classification = "low"
    elif severity < 0.7:
        classification = "medium"
    else:
        classification = "high"

    chain.append({
        "cgroup": cgroup,
        "throttle_us": throttle_us,
        "effective_cpu_us": eff_cpu,
        "severity": round(severity, 4),
        "classification": classification,
        "depth_from_origin": 0
    })

    if scope == "subtree":
        # BFS propagation
        queue = [(c, 1, throttle_us) for c in get_children(cgroup)]
        while queue:
            node, depth_from_orig, parent_throttle = queue.pop(0)
            child_throttle = math.floor(parent_throttle * decay)
            node_eff_cpu = get_effective_cpu(node)
            node_severity = child_throttle / node_eff_cpu if node_eff_cpu > 0 else 0.0
            if node_severity < 0.3:
                node_class = "low"
            elif node_severity < 0.7:
                node_class = "medium"
            else:
                node_class = "high"

            chain.append({
                "cgroup": node,
                "throttle_us": child_throttle,
                "effective_cpu_us": node_eff_cpu,
                "severity": round(node_severity, 4),
                "classification": node_class,
                "depth_from_origin": depth_from_orig
            })

            for grandchild in get_children(node):
                queue.append((grandchild, depth_from_orig + 1, child_throttle))

    chain.sort(key=lambda x: (x["depth_from_origin"], x["cgroup"]))

    # Find max severity
    max_sev = max(chain, key=lambda x: x["severity"])

    throttle_chains.append({
        "event_id": evt["id"],
        "origin_cgroup": cgroup,
        "chain": chain,
        "total_affected": len(chain),
        "max_severity": max_sev["classification"]
    })

throttle_chains.sort(key=lambda x: x["event_id"])

# Rule 8: Summary
total_cgroups = len(all_nodes)
total_leaf = len(leaf_cgroups)
total_processes = len(processes["processes"])
total_killed = len(killed_pids)
total_freed = sum(entry["total_memory_freed_bytes"] for entry in oom_kill_log)
capped_cpu = sum(1 for e in effective_limits if e["capped_by_cpu"] is not None)
capped_mem = sum(1 for e in effective_limits if e["capped_by_memory"] is not None)
oc_warnings = sum(1 for e in overcommit_analysis if e["cpu_status"] == "warning" or e["memory_status"] == "warning")
oc_criticals = sum(1 for e in overcommit_analysis if e["cpu_status"] == "critical" or e["memory_status"] == "critical")
total_pressure = len(pressure_events["events"])
total_oom_events = sum(1 for e in pressure_events["events"] if e["type"] == "memory_pressure" and e["level"] == "critical")
total_throttle = sum(1 for e in pressure_events["events"] if e["type"] == "cpu_throttle")
post_resolved = sum(1 for e in post_oom_state if e["status"] == "resolved")
post_unresolved = sum(1 for e in post_oom_state if e["status"] == "unresolved")

# Max throttle severity across all chains
all_severities = []
for tc in throttle_chains:
    for entry in tc["chain"]:
        all_severities.append(entry["severity"])

if all_severities:
    max_sev_val = max(all_severities)
    if max_sev_val < 0.3:
        max_throttle_sev = "low"
    elif max_sev_val < 0.7:
        max_throttle_sev = "medium"
    else:
        max_throttle_sev = "high"
else:
    max_throttle_sev = "none"

summary = {
    "total_cgroups": total_cgroups,
    "total_leaf_cgroups": total_leaf,
    "total_processes": total_processes,
    "total_processes_killed": total_killed,
    "total_memory_freed_bytes": total_freed,
    "cgroups_capped_by_ancestor_cpu": capped_cpu,
    "cgroups_capped_by_ancestor_memory": capped_mem,
    "overcommit_warnings": oc_warnings,
    "overcommit_criticals": oc_criticals,
    "total_pressure_events": total_pressure,
    "total_oom_events": total_oom_events,
    "total_throttle_events": total_throttle,
    "post_oom_resolved_count": post_resolved,
    "post_oom_unresolved_count": post_unresolved,
    "max_throttle_severity": max_throttle_sev
}

report = {
    "effective_limits": effective_limits,
    "cpu_distribution": cpu_distribution,
    "overcommit_analysis": overcommit_analysis,
    "pressure_responses": pressure_responses,
    "oom_kill_log": oom_kill_log,
    "post_oom_state": post_oom_state,
    "throttle_chains": throttle_chains,
    "summary": summary
}

output = json.dumps(report, indent=2, sort_keys=True)
with open("/app/cgroup_hierarchy_report.json", "w") as f:
    f.write(output)

print("Cgroup resource cascade audit complete. Report written to /app/cgroup_hierarchy_report.json")
