def load_json(path):
    with open(path) as f:
        return json.load(f)

def hex_to_int(s):
    return int(s, 16)

def int_to_hex(n):
    return "0x" + format(n, '016x')

config = load_json("/app/coredump/config.json")
process_info = load_json("/app/coredump/process_info.json")
memory_mappings = load_json("/app/coredump/memory_mappings.json")["mappings"]
