threads.sort(key=lambda t: t["thread_id"])

freed_allocs = [a for a in heap_allocs if a["state"] == "freed"]

def find_mapping(addr):
    for m in memory_mappings:
        base = hex_to_int(m["base_address"])
        end = hex_to_int(m["end_address"])
        if base <= addr < end:
            return m
    return None

def resolve_symbol(addr):
    mapping = find_mapping(addr)
    if mapping is None:
        return None, "unknown", None
    lib = mapping["library"]
    base = hex_to_int(mapping["base_address"])
    load_off = hex_to_int(mapping["load_offset"])
    effective_offset = addr - base + load_off
    if lib in symbols:
        for sym in symbols[lib]:
            sym_off = hex_to_int(sym["offset"])
            sym_size = sym["size"]
            if sym_off <= effective_offset < sym_off + sym_size:
                return sym["name"], lib, effective_offset
    return None, lib, effective_offset

# Rule 3: Corruption detection - find tainted frames
thread_taint = {}
for t in threads:
    frames = t["stack_frames"]
    tainted = [False] * len(frames)
    corruption_idx = None
    for i in range(len(frames) - 1, -1, -1):
        if not frames[i]["canary_intact"]:
            corruption_idx = i
            break
    if corruption_idx is not None:
        for i in range(0, corruption_idx + 1):
            tainted[i] = True
    thread_taint[t["thread_id"]] = {
        "tainted": tainted,
        "corruption_idx": corruption_idx
    }

# Rule 1 & 2: Stack traces with symbol resolution
stack_traces = []
all_frame_resolutions = {}

for t in threads:
    tid = t["thread_id"]
    tainted_flags = thread_taint[tid]["tainted"]
    frames_out = []
    for i, f in enumerate(t["stack_frames"]):
        addr = hex_to_int(f["return_address"])
        sym_name, lib, eff_off = resolve_symbol(addr)
        frame_entry = {
            "effective_offset": int_to_hex(eff_off) if eff_off is not None else "0x0000000000000000",
            "frame_id": f["frame_id"],
            "library": lib,
            "return_address": f["return_address"],
            "symbol": sym_name if sym_name else "??",
            "tainted": tainted_flags[i]
        }
        frames_out.append(frame_entry)
        all_frame_resolutions[(tid, f["frame_id"])] = {
            "resolved": sym_name is not None,
            "tainted": tainted_flags[i],
            "library": lib,
            "addr": addr
        }
    stack_traces.append({
        "frames": frames_out,
        "thread_id": tid,
        "thread_name": t["name"]
    })

stack_traces.sort(key=lambda x: x["thread_id"])

# Rule 6: Symbol resolution summary
total_frames = 0
resolved_count = 0
unresolved_count = 0
tainted_count = 0
per_thread = {}

for t in threads:
    tid = t["thread_id"]
    t_total = len(t["stack_frames"])
    t_resolved = 0
    t_unresolved = 0
    t_tainted = 0
    for i, f in enumerate(t["stack_frames"]):
        key = (tid, f["frame_id"])
        info = all_frame_resolutions[key]
        if info["tainted"]:
            t_tainted += 1
        elif info["resolved"]:
            t_resolved += 1
        else:
            t_unresolved += 1
    per_thread[tid] = {
        "resolved": t_resolved,
        "tainted": t_tainted,
        "total": t_total,
        "unresolved": t_unresolved
    }
    total_frames += t_total
    resolved_count += t_resolved
    unresolved_count += t_unresolved
    tainted_count += t_tainted

denom = resolved_count + unresolved_count
resolution_rate = round(resolved_count / denom, 4) if denom > 0 else 0.0

symbol_resolution = {
    "per_thread": per_thread,
    "resolution_rate": resolution_rate,
    "resolved_count": resolved_count,
    "tainted_count": tainted_count,
    "total_frames": total_frames,
    "unresolved_count": unresolved_count
}

# Rule 4: Corruption analysis
corrupted_threads_list = []
for t in threads:
    tid = t["thread_id"]
    ci = thread_taint[tid]["corruption_idx"]
    if ci is not None:
        corrupted_threads_list.append({
            "corruption_frame_id": t["stack_frames"][ci]["frame_id"],
            "corruption_frame_index": ci,
            "corruption_type": "stack_buffer_overflow",
            "tainted_frame_count": ci + 1,
            "thread_id": tid,
            "thread_name": t["name"],
            "total_frame_count": len(t["stack_frames"])
        })
corrupted_threads_list.sort(key=lambda x: x["thread_id"])

# Heap anomalies: check registers of threads whose top frame is NOT tainted
heap_anomalies = []
for t in threads:
    tid = t["thread_id"]
    tainted_flags = thread_taint[tid]["tainted"]
    if len(tainted_flags) > 0 and tainted_flags[0]:
        continue
    regs = t["registers"]
    seen_allocs = set()
    for reg_name in ["rdi", "rsi", "rbx"]:
        reg_val = hex_to_int(regs[reg_name])
