            if alloc_addr <= reg_val < alloc_addr + alloc["size"]:
                if alloc["alloc_id"] not in seen_allocs:
                    seen_allocs.add(alloc["alloc_id"])
                    heap_anomalies.append({
                        "address": alloc["address"],
                        "alloc_id": alloc["alloc_id"],
                        "anomaly_type": "use_after_free",
