                        "tag": alloc["tag"]
                    })

heap_anomalies.sort(key=lambda x: (x["alloc_id"], x["referencing_thread"]))

corruption_analysis = {
    "corrupted_threads": corrupted_threads_list,
    "heap_anomalies": heap_anomalies,
    "total_corrupted_threads": len(corrupted_threads_list),
    "total_heap_anomalies": len(heap_anomalies)
}

# Rule 5: Thread classification
def get_signal_info(sig_name):
    if sig_name and sig_name in signals_def:
        return signals_def[sig_name]
