thread_classification = []
for t in threads:
    tid = t["thread_id"]
    sig = t.get("signal_received")
    sig_info = get_signal_info(sig)
    has_taint = any(thread_taint[tid]["tainted"])

    is_faulting = (sig is not None and
                   sig == process_info["dump_reason"] and
                   t.get("fault_address") is not None)

    if sig_info and sig_info["severity"] == "fatal" and sig_info["default_action"] == "core":
        classification = "crashed"
    elif sig is not None and sig_info:
        classification = "signal_received"
    elif has_taint:
        classification = "corrupted"
    elif t["state"] == "blocked":
