corrupted_count = sum(1 for tc in thread_classification if tc["classification"] == "corrupted")
blocked_count = sum(1 for tc in thread_classification if tc["classification"] == "blocked")
running_count = sum(1 for tc in thread_classification if tc["classification"] == "running")
