            if w not in indices:
                strongconnect(w)
                lowlinks[v] = min(lowlinks[v], lowlinks[w])
            elif w in on_stack:
                lowlinks[v] = min(lowlinks[v], indices[w])
        if lowlinks[v] == indices[v]:
            comp = []
            while True:
                w = stack.pop()
                on_stack.discard(w)
                comp.append(w)
                if w == v:
                    break
            sccs.append(comp)

    import sys as _sys
    _sys.setrecursionlimit(10000)
    for v in nodes:
        if v not in indices:
            strongconnect(v)
    return sccs

scc_adj = {}
for ref in references_data:
    if ref["ref_type"] == "strong":
        scc_adj.setdefault(ref["from_alloc"], []).append(ref["to_alloc"])
    elif (ref["from_alloc"], ref["to_alloc"]) in strengthened_weak:
        scc_adj.setdefault(ref["from_alloc"], []).append(ref["to_alloc"])

scc_list = tarjan_scc(sorted(allocs.keys()), scc_adj)
strong_cycle_components = [sorted(c) for c in scc_list if len(c) >= 2]
strong_cycle_components.sort(key=lambda c: c[0])

cycle_member_to_index = {}
for idx, comp in enumerate(strong_cycle_components):
    for m in comp:
        cycle_member_to_index[m] = idx

reachable_after_phantom = set(valid_paths.keys()) | set(non_phantom_roots)

strong_cycles = []
for idx, comp in enumerate(strong_cycle_components):
    comp_set = set(comp)
    anchor_roots = set()
    for ref in references_data:
        src, dst = ref["from_alloc"], ref["to_alloc"]
        if ref["ref_type"] == "strong":
            pass
        elif (src, dst) in strengthened_weak:
            pass
        else:
            continue
        if (src, dst) in decayed_refs:
            continue
        if dst in comp_set and src not in comp_set and src in reachable_after_phantom:
            for nr in non_phantom_roots:
                if nr == src or (src in valid_paths and valid_paths[src][1] == nr):
                    anchor_roots.add(nr)
    anchored = bool(anchor_roots)
    anchor_root = min(anchor_roots) if anchored else None
    cycle_owners = sorted({effective_owner[m] for m in comp})
    cycle_size = sum(effective_size_map[m] for m in comp)
    strong_cycles.append({
        "anchor_root": anchor_root,
        "anchored": anchored,
        "cycle_id": f"SC{idx+1:03d}",
        "members": comp,
        "owners": cycle_owners,
        "total_effective_size": cycle_size
    })

unanchored_cycle_count = sum(1 for c in strong_cycles if not c["anchored"])

# ============================================================
# Rule 8: Leak Summary
# ============================================================
total_freed = sum(1 for s in status_map.values() if s in ("freed", "deferred_freed"))
total_live = sum(1 for s in status_map.values() if s in ("live", "deferred_pending"))
total_leaked = len(leaked_allocs)
total_reachable = len(reachability_chains)
leaked_bytes = sum(effective_size_map[aid] for aid in leaked_allocs)
largest_component = max((lc["total_effective_size"] for lc in leak_chains), default=0)
deferred_activated = sum(1 for d in deferred_free_log if d["activated"])

leak_summary = {
    "decayed_reference_count": decayed_reference_count,
    "deferred_frees_activated": deferred_activated,
    "largest_leak_component_size": largest_component,
    "leaked_bytes": leaked_bytes,
    "ownership_transfers_applied": len(transfers_data),
    "phantom_root_count": len(phantom_roots_list),
    "strengthened_weak_count": strengthened_weak_count,
    "strong_cycle_count": len(strong_cycles),
    "total_allocations": len(allocs),
    "total_freed": total_freed,
    "total_leaked": total_leaked,
    "total_live": total_live,
    "total_reachable": total_reachable,
    "unanchored_cycle_count": unanchored_cycle_count
}

# ============================================================
# Build final report
# ============================================================
report = {
    "allocation_status": allocation_status,
    "deferred_free_log": deferred_free_log,
    "leak_chains": leak_chains,
    "leak_summary": leak_summary,
    "ownership_graph": {aid: effective_owner[aid] for aid in sorted(allocs.keys())},
    "phantom_roots": phantom_roots_output,
    "reachability_chains": reachability_chains,
    "strong_cycles": strong_cycles
}

with open(OUTPUT_FILE, "w") as f:
    f.write(json.dumps(report, indent=2, sort_keys=True))

print("Memory leak profiler report generated successfully.")
